import { addCommonRoleOptions, commonRoleOptions } from './utils.js';
export const underlineRole = {
    name: 'underline',
    alias: ['u'],
    options: { ...commonRoleOptions('underline') },
    body: {
        type: 'myst',
        required: true,
    },
    run(data) {
        const node = { type: 'underline', children: data.body };
        addCommonRoleOptions(data, node);
        return [node];
    },
};
