import { addCommonRoleOptions, commonRoleOptions } from './utils.js';
export const subscriptRole = {
    name: 'subscript',
    alias: ['sub'],
    options: { ...commonRoleOptions('subscript') },
    body: {
        type: 'myst',
        required: true,
    },
    run(data) {
        const node = { type: 'subscript', children: data.body };
        addCommonRoleOptions(data, node);
        return [node];
    },
};
